"""Business logic layer for warehouse inventory management.

Coordinates between the API, validation, and storage layers.
Stock-level rules, reorder logic, and allocation live here.

BUG 4 is here: check_reorder and list_low_stock use < instead of <=,
so stock exactly AT the reorder threshold does not trigger a reorder.
"""

from validation import InventoryValidator
from storage import InventoryStorage


class InventoryLogic:
    """Core business logic for inventory operations."""

    def __init__(self):
        self.validator = InventoryValidator()
        self.storage = InventoryStorage()

    def create_item(self, sku: str, name: str, quantity: int,
                    reorder_threshold: int, warehouse_capacity: int) -> dict:
        """Validate and persist a new inventory item."""
        sku = sku.lower()

        err = self.validator.validate_sku(sku)
        if err:
            return {"status": "error", "error": err}
        err = self.validator.validate_quantity(quantity)
        if err:
            return {"status": "error", "error": err}
        err = self.validator.validate_reorder_threshold(reorder_threshold)
        if err:
            return {"status": "error", "error": err}
        if self.storage.exists(sku):
            return {"status": "error", "error": f"Item {sku!r} already exists"}

        item = {
            "sku": sku, "name": name, "quantity": quantity,
            "reorder_threshold": reorder_threshold,
            "warehouse_capacity": warehouse_capacity,
        }
        self.storage.save(sku, item)
        return {"status": "ok", "item": item}

    def get_item(self, sku: str) -> dict:
        """Retrieve an item record by SKU (exact key match)."""
        item = self.storage.load(sku)
        if item is None:
            return {"status": "error", "error": f"Item {sku!r} not found"}
        return {"status": "ok", "item": item}

    def update_quantity(self, sku: str, quantity: int) -> dict:
        """Admin override: write a new stock level directly."""
        item = self.storage.load(sku)
        if item is None:
            return {"status": "error", "error": f"Item {sku!r} not found"}
        err = self.validator.validate_quantity(quantity)
        if err:
            return {"status": "error", "error": err}
        item["quantity"] = quantity
        self.storage.save(sku, item)
        return {"status": "ok", "quantity": quantity}

    def restock(self, sku: str, incoming: int) -> dict:
        """Add incoming units to stock, checking warehouse capacity.

        BUG 1 is triggered here: validate_capacity (in validation.py)
        uses > instead of >=, so a restock that brings quantity to
        exactly warehouse_capacity is incorrectly allowed.
        """
        item = self.storage.load(sku)
        if item is None:
            return {"status": "error", "error": f"Item {sku!r} not found"}
        new_quantity = item["quantity"] + incoming
        err = self.validator.validate_capacity(new_quantity,
                                               item["warehouse_capacity"])
        if err:
            return {"status": "error", "error": err}
        item["quantity"] = new_quantity
        self.storage.save(sku, item)
        return {"status": "ok", "new_quantity": new_quantity}

    def allocate(self, sku: str, quantity: int) -> dict:
        """Reserve stock for an order using a storage transaction.

        The transaction is meant to make the read-check-write atomic.
        BUG 3 is in storage.py: commit() clobbers intermediate writes.
        """
        err = self.validator.validate_quantity(quantity)
        if err:
            return {"status": "error", "error": err}
        txn = self.storage.begin_transaction(sku)
        if txn is None:
            return {"status": "error", "error": f"Item {sku!r} not found"}
        item = txn["item"]
        if item["quantity"] < quantity:
            self.storage.rollback(txn)
            return {"status": "error", "error": "Insufficient stock",
                    "available": item["quantity"]}
        item["quantity"] -= quantity
        self.storage.commit(txn)
        return {"status": "ok", "allocated": quantity,
                "remaining": item["quantity"]}

    def check_reorder(self, sku: str) -> dict:
        """Check whether an item needs reordering.

        BUG 4: uses < instead of <=.
        Stock exactly AT threshold should trigger reorder; currently doesn't.
        Fix: change  quantity < reorder_threshold
             to      quantity <= reorder_threshold
        """
        item = self.storage.load(sku)
        if item is None:
            return {"status": "error", "error": f"Item {sku!r} not found"}
        needs_reorder = item["quantity"] < item["reorder_threshold"]  # BUG 4
        return {
            "status": "ok",
            "needs_reorder": needs_reorder,
            "current_stock": item["quantity"],
            "reorder_threshold": item["reorder_threshold"],
        }

    def list_low_stock(self) -> dict:
        """Return all items at or below their reorder threshold.

        BUG 4: uses < instead of <=, excluding items where
        stock == threshold.  Fix: change < to <=.
        """
        all_items = self.storage.load_all()
        low = [it for it in all_items
               if it["quantity"] < it["reorder_threshold"]]  # BUG 4
        return {"status": "ok", "items": low}
